import { useEffect, useState } from "react";
import { FundSearch } from "./components/FundSearch";
import { FundLists } from "./components/FundLists";
import { ListDetail } from "./components/ListDetail";
import { useTauriCommands } from "./hooks/useTauriCommands";
import { FundList } from "./types";
import { useToast } from "./components/ToastContext";
import "./App.css";

function App() {
  const showToast = useToast();
  const [lists, setLists] = useState<FundList[]>([]);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);
  const [listsError, setListsError] = useState<string | null>(null);
  const [listRefreshKey, setListRefreshKey] = useState(0);
  const { getAllLists } = useTauriCommands();

  // 加载所有列表
  const loadLists = async () => {
    try {
      const allLists = await getAllLists();
      setLists(allLists);
      setListsError(null);
    } catch (error) {
      console.error("Failed to load lists:", error);
      setLists([]);
      setListsError(
        "数据加载失败，可能已损坏，已使用空列表。请检查备份文件。"
      );
    }
  };

  const handleListsChange = async () => {
    await loadLists();
    setListRefreshKey((value) => value + 1);
  };

  useEffect(() => {
    loadLists();
  }, []);

  const selectedList = lists.find((l) => l.id === selectedListId);

  return (
    <div className="app-container">
      <div className="left-section">
        {listsError && <div className="list-error">{listsError}</div>}
        <FundLists
          lists={lists}
          selectedListId={selectedListId}
          onSelectList={setSelectedListId}
          onListsChange={handleListsChange}
          showToast={showToast}
        />
      </div>

      <div className="middle-section">
        <div className="search-section">
          <h2>🔍 搜索基金</h2>
          <FundSearch
            lists={lists}
            onListsChange={handleListsChange}
            showToast={showToast}
          />
        </div>
      </div>

      <div className="right-section">
        <ListDetail
          listId={selectedListId}
          listName={selectedList?.name || ""}
          onListsChange={handleListsChange}
          showToast={showToast}
          refreshKey={listRefreshKey}
        />
      </div>
    </div>
  );
}

export default App;

