import React, { useEffect, useState } from "react";
import { FundInfo } from "../types";
import { useTauriCommands } from "../hooks/useTauriCommands";

interface ListDetailViewProps {
  listId: string | null;
  listName: string;
  showToast?: (message: string, type: "success" | "error") => void;
  onListsChange: () => void;
}

export const ListDetailView: React.FC<ListDetailViewProps> = ({
  listId,
  listName,
  showToast,
  onListsChange,
}) => {
  const [funds, setFunds] = useState<FundInfo[]>([]);
  const [loading, setLoading] = useState(false);
  const { getListFunds, removeFundFromList } = useTauriCommands();

  useEffect(() => {
    if (listId) {
      loadFunds();
    } else {
      setFunds([]);
    }
  }, [listId]);

  const loadFunds = async () => {
    if (!listId) return;

    setLoading(true);
    try {
      const fundList = await getListFunds(listId);
      setFunds(fundList);
    } catch (error) {
      if (showToast) {
        showToast(String(error), "error");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRemove = async (fundCode: string) => {
    if (!listId) return;

    if (!confirm(`确定从列表中移除基金 ${fundCode} 吗？`)) {
      return;
    }

    try {
      await removeFundFromList(listId, fundCode);
      if (showToast) {
        showToast("已从列表中移除", "success");
      }
      loadFunds();
      onListsChange();
    } catch (error) {
      if (showToast) {
        showToast(String(error), "error");
      }
    }
